import pika
import subprocess
import json
import sys
import os

def process_job_message(ch, method, properties, body):
    try:
        # Parse the message body as JSON
        message = json.loads(body)
        command = message.get('command')
        
        if not command:
            print("No command found in message")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
            return
            
        # Validate command - check for dangerous patterns
        dangerous_patterns = [';', '&', '|', '&&', '||', '`', '$(', '${', 'exec', 'system']
        for pattern in dangerous_patterns:
            if pattern in command:
                print(f"Potentially dangerous command pattern detected: {pattern}")
                ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
                return
                
        # Execute the command safely
        result = subprocess.run(
            command,
            shell=True,
            capture_output=True,
            text=True,
            timeout=300  # 5 minute timeout
        )
        
        print(f"Command executed: {command}")
        print(f"Return code: {result.returncode}")
        if result.stdout:
            print(f"Output: {result.stdout}")
        if result.stderr:
            print(f"Error: {result.stderr}")
            
        ch.basic_ack(delivery_tag=method.delivery_tag)
        
    except subprocess.TimeoutExpired:
        print("Command timed out")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
    except json.JSONDecodeError:
        print("Invalid JSON in message")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
    except Exception as e:
        print(f"Error processing message: {str(e)}")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)

def main():
    # Establish connection to RabbitMQ
    connection = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
    channel = connection.channel()
    
    # Declare the queue
    channel.queue_declare(queue='job_queue', durable=True)
    
    # Set up consumer
    channel.basic_qos(prefetch_count=1)
    channel.basic_consume(queue='job_queue', on_message_callback=process_job_message)
    
    print("Waiting for messages. To exit press CTRL+C")
    try:
        channel.start_consuming()
    except KeyboardInterrupt:
        print("Stopping consumer...")
        channel.stop_consuming()
        connection.close()

if __name__ == "__main__":
    main()